import{_ as n,o as i,c as a,ag as t}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Kundenportal","description":"","frontmatter":{},"headers":[],"relativePath":"de/advanced/customer-portal.md","filePath":"de/advanced/customer-portal.md"}'),r={name:"de/advanced/customer-portal.md"};function l(s,e,o,u,h,d){return i(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="kundenportal" tabindex="-1">Kundenportal <a class="header-anchor" href="#kundenportal" aria-label="Permalink to &quot;Kundenportal&quot;">​</a></h1><p>Das Kundenportal ermöglicht es Ihren Kunden, Rechnungen online über eine sichere, gebrandete Oberfläche einzusehen und zu bezahlen.</p><h2 id="so-funktioniert-es" tabindex="-1">So funktioniert es <a class="header-anchor" href="#so-funktioniert-es" aria-label="Permalink to &quot;So funktioniert es&quot;">​</a></h2><p>Wenn Sie eine Rechnung versenden, wird ein eindeutiger <strong>Zahlungslink</strong> generiert. Wenn Ihr Kunde auf diesen Link klickt, wird er zum Kundenportal weitergeleitet, wo er:</p><ol><li><strong>Die Rechnung ansehen</strong> kann — Alle Details, Positionen und Gesamtbeträge einsehen</li><li><strong>Das PDF herunterladen</strong> kann — Eine Kopie der Rechnung erhalten</li><li><strong>Online bezahlen</strong> kann — Die Zahlung direkt über das Portal abschließen</li><li><strong>Zahlung bestätigen</strong> kann — Eine Banküberweisung bestätigen</li></ol><h2 id="portal-funktionen" tabindex="-1">Portal-Funktionen <a class="header-anchor" href="#portal-funktionen" aria-label="Permalink to &quot;Portal-Funktionen&quot;">​</a></h2><h3 id="rechnungsansicht" tabindex="-1">Rechnungsansicht <a class="header-anchor" href="#rechnungsansicht" aria-label="Permalink to &quot;Rechnungsansicht&quot;">​</a></h3><p>Das Portal zeigt eine übersichtliche, gebrandete Ansicht der Rechnung, einschließlich:</p><ul><li>Ihr Firmenlogo und Branding</li><li>Rechnungsnummer und Datum</li><li>Positionen mit Beschreibungen und Beträgen</li><li>USt.-Aufschlüsselung</li><li>Fälliger Gesamtbetrag</li><li>Fälligkeitsdatum</li></ul><h3 id="zahlung" tabindex="-1">Zahlung <a class="header-anchor" href="#zahlung" aria-label="Permalink to &quot;Zahlung&quot;">​</a></h3><p>Kunden können direkt über das Portal bezahlen. Wenn die Zahlung bestätigt wird, aktualisiert sich der Rechnungsstatus in Ihrem Dashboard automatisch auf <strong>Bezahlt</strong>.</p><h3 id="branding" tabindex="-1">Branding <a class="header-anchor" href="#branding" aria-label="Permalink to &quot;Branding&quot;">​</a></h3><p>Das Kundenportal verwendet Ihr Unternehmensbranding:</p><ul><li>Firmenlogo</li><li>Akzentfarbe</li><li>Unternehmensinformationen</li></ul><p>Dies schafft ein professionelles, konsistentes Erlebnis für Ihre Kunden.</p><h2 id="zugangssicherheit" tabindex="-1">Zugangssicherheit <a class="header-anchor" href="#zugangssicherheit" aria-label="Permalink to &quot;Zugangssicherheit&quot;">​</a></h2><p>Jeder Portal-Link ist:</p><ul><li><strong>Eindeutig</strong> — Pro Rechnung generiert</li><li><strong>Token-basiert</strong> — Mit einem einzigartigen Zugangstoken gesichert</li><li><strong>Rechnungsspezifisch</strong> — Zeigt nur die spezifische Rechnung</li></ul><p>Kunden benötigen kein MyCompanyDesk-Konto, um Rechnungen einzusehen und zu bezahlen.</p><h2 id="kundenereignis-tracking" tabindex="-1">Kundenereignis-Tracking <a class="header-anchor" href="#kundenereignis-tracking" aria-label="Permalink to &quot;Kundenereignis-Tracking&quot;">​</a></h2><p>MyCompanyDesk verfolgt Kundeninteraktionen mit dem Portal:</p><ul><li>Wann der Kunde die Rechnung öffnet</li><li>Wann er das PDF herunterlädt</li><li>Wann er die Zahlung einleitet</li><li>Wann die Zahlung bestätigt wird</li></ul><p>Dies hilft Ihnen, das Kundenengagement zu verstehen und effektiv nachzufassen.</p><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Fügen Sie Ihrer Rechnungs-E-Mail eine persönliche Notiz hinzu, um die Portal-Nutzung zu fördern</li><li>Das Portal funktioniert auf allen Geräten — Mobiltelefon, Tablet und Desktop</li><li>Zahlungsbestätigungen werden sowohl an Sie als auch an den Kunden gesendet</li><li>Prüfen Sie den Kundenereignisverlauf auf der Rechnungsdetailseite, um Portal-Interaktionen einzusehen</li></ul>',25)])])}const p=n(r,[["render",l]]);export{c as __pageData,p as default};
